const gemini = $input.first().json;
const prev = $('Rate Limit').first().json;
let a = {};
try {
  let t = gemini.candidates[0].content.parts[0].text;
  const m = t.match(/\{[\s\S]*\}/);
  if (m) a = JSON.parse(m[0]);
} catch(e) {
  a = {kategori:'Diger',duygu:'Notr',oncelik:'Orta',ozet:'Analiz yapilamadi',oto_yanit:false,yanit:'',eylem:'Manuel kontrol'};
}
const kritik = (a.oncelik==='Yuksek'||a.duygu==='Sinirli');
const otoOk = (a.oto_yanit===true && a.yanit && prev.kanal==='Telegram' && prev.chatId);
return [{json:{...prev,kategori:a.kategori||'Diger',duygu:a.duygu||'Notr',oncelik:a.oncelik||'Orta',ozet:a.ozet||'',oto_yanit_durum:otoOk?'Evet':'Hayir',yanit:a.yanit||'',eylem:a.eylem||'',kritik,otoOk}}];

const d = $input.first().json;
